div.script:
document.addEventListener('DOMContentLoaded', function () {
    var STORAGE_KEY = 'baf_saved_carts_v4';
    var cartRoot = document.getElementById('shop_cart');

    if (!cartRoot) {
        return;
    }

    function showStatus(message, type) {
        var box = document.getElementById('bafCartStatus');

        if (!box) {
            return;
        }

        box.hidden = false;
        box.textContent = message;
        box.classList.remove('is-success');
        box.classList.remove('is-error');

        if (type === 'error') {
            box.classList.add('is-error');
        } else {
            box.classList.add('is-success');
        }

        window.setTimeout(function () {
            box.hidden = true;
        }, 5000);
    }

    function escapeHtml(value) {
        return String(value == null ? '' : value)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#039;');
    }

    function formatDateForFilename(date) {
        var year = date.getFullYear();
        var month = String(date.getMonth() + 1).padStart(2, '0');
        var day = String(date.getDate()).padStart(2, '0');

        return year + '-' + month + '-' + day;
    }

    function csvEscape(value) {
        value = String(value == null ? '' : value);
        return '"' + value.replace(/"/g, '""') + '"';
    }

    function getSavedCarts() {
        var raw = localStorage.getItem(STORAGE_KEY);

        if (!raw) {
            return [];
        }

        try {
            var carts = JSON.parse(raw);
            return Array.isArray(carts) ? carts : [];
        } catch (error) {
            return [];
        }
    }

    function setSavedCarts(carts) {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(carts || []));
    }

    function makeCartId() {
        return 'cart_' + Date.now() + '_' + Math.floor(Math.random() * 100000);
    }

    function parseUrlParamFromText(text, key) {
        var regex = new RegExp('[?&]' + key + '=([^&#]+)');
        var match = String(text || '').match(regex);

        if (!match) {
            return '';
        }

        return decodeURIComponent(match[1].replace(/\+/g, ' '));
    }

    function findProductId(row) {
        var direct = row.getAttribute('data-product-id') ||
            row.getAttribute('data-product_id') ||
            row.dataset.productId ||
            '';

        if (direct) {
            return direct;
        }

        var input = row.querySelector('[name="product_id"], input[data-product-id], input[data-product_id]');

        if (input) {
            return input.value ||
                input.getAttribute('data-product-id') ||
                input.getAttribute('data-product_id') ||
                '';
        }

        var links = row.querySelectorAll('a[href*="/shop/cart/update"]');

        for (var i = 0; i < links.length; i++) {
            var href = links[i].getAttribute('href') || '';
            var productId = parseUrlParamFromText(href, 'product_id');

            if (productId) {
                return productId;
            }
        }

        return '';
    }

    function findLineId(row) {
        var direct = row.getAttribute('data-line-id') ||
            row.getAttribute('data-line_id') ||
            row.dataset.lineId ||
            '';

        if (direct) {
            return direct;
        }

        var input = row.querySelector('[name="line_id"], input[data-line-id], input[data-line_id]');

        if (input) {
            return input.value ||
                input.getAttribute('data-line-id') ||
                input.getAttribute('data-line_id') ||
                '';
        }

        var links = row.querySelectorAll('a[href*="/shop/cart/update"]');

        for (var i = 0; i < links.length; i++) {
            var href = links[i].getAttribute('href') || '';
            var lineId = parseUrlParamFromText(href, 'line_id');

            if (lineId) {
                return lineId;
            }
        }

        return '';
    }

    function findQuantity(row) {
        var input = row.querySelector('input.js_quantity, input.quantity, input[name="add_qty"], input[type="number"]');

        if (input) {
            var value = parseFloat(String(input.value || '0').replace(',', '.'));

            if (Number.isFinite(value) && value > 0) {
                return value;
            }
        }

        var qtyText = '';
        var qtyCell = row.querySelector('.td-qty, .td_quantity, [class*="quantity"], [class*="qty"]');

        if (qtyCell) {
            qtyText = qtyCell.textContent || '';
        }

        var qtyMatch = String(qtyText).match(/\d+(?:[,.]\d+)?/);

        if (qtyMatch) {
            var qty = parseFloat(qtyMatch[0].replace(',', '.'));

            if (Number.isFinite(qty) && qty > 0) {
                return qty;
            }
        }

        return 1;
    }

    function findPartNumber(row) {
        var text = '';

        var possible = row.querySelector('[data-part-number], .baf-cart-part, .td-product_name, .td-product-name, .td-product, .o_wsale_cart_item_title');

        if (possible) {
            text = possible.getAttribute('data-part-number') || possible.textContent || '';
        } else {
            text = row.textContent || '';
        }

        var match = String(text).match(/[A-Z0-9_\/.-]{5,}/i);

        return match ? match[0].trim() : '';
    }

    function findProductName(row) {
        var selectors = [
            '.td-product_name a',
            '.td-product_name',
            '.td-product-name',
            '.td-product',
            '.o_wsale_cart_item_title',
            'h6',
            'h5',
            'strong'
        ];

        for (var i = 0; i < selectors.length; i++) {
            var el = row.querySelector(selectors[i]);

            if (el && el.textContent.trim()) {
                return el.textContent.trim();
            }
        }

        return row.textContent.trim().replace(/\s+/g, ' ').slice(0, 120);
    }

    function getCartRows() {
        var selectors = [
            '.baf-original-cart-wrap tbody tr',
            '.baf-original-cart-wrap .cart_line',
            '.baf-original-cart-wrap .o_cart_product',
            '.baf-original-cart-wrap .o_wsale_cart_line',
            '.baf-original-cart-wrap .o_wsale_cart_item'
        ];

        var rows = [];

        selectors.forEach(function (selector) {
            document.querySelectorAll(selector).forEach(function (row) {
                if (rows.indexOf(row) === -1 && findProductId(row)) {
                    rows.push(row);
                }
            });
        });

        return rows;
    }

    function getCartItems() {
        var rows = getCartRows();
        var items = [];

        rows.forEach(function (row) {
            var productId = findProductId(row);
            var lineId = findLineId(row);
            var qty = findQuantity(row);

            if (!productId || !Number.isFinite(qty) || qty <= 0) {
                return;
            }

            items.push({
                product_id: productId,
                line_id: lineId,
                quantity: qty,
                part_number: findPartNumber(row),
                name: findProductName(row)
            });
        });

        return items;
    }

    function getCartItemsForExport() {
        var items = getCartItems();

        return items.map(function (item, index) {
            return {
                position: index + 1,
                part_number: item.part_number || '',
                name: item.name || '',
                quantity: item.quantity || ''
            };
        });
    }

    function disableProductPageLinks() {
        cartRoot.querySelectorAll('.baf-original-cart-wrap a').forEach(function (link) {
            var href = link.getAttribute('href') || '';

            if (
                href.indexOf('/shop/cart/update') !== -1 ||
                href.indexOf('/shop/checkout') !== -1 ||
                href.indexOf('/shop/cart') !== -1 ||
                href.indexOf('/payment') !== -1
            ) {
                return;
            }

            if (href.indexOf('/shop/') !== -1 || link.closest('.td-product_name')) {
                link.removeAttribute('href');
                link.style.cursor = 'default';
                link.style.pointerEvents = 'none';
                link.style.color = 'inherit';
                link.style.textDecoration = 'none';
            }
        });
    }

    async function clearCartWithoutConfirm(reloadAfterClear) {
        var items = getCartItems();

        for (var i = 0; i < items.length; i++) {
            var url = '/shop/cart/update?product_id=' +
                encodeURIComponent(items[i].product_id) +
                '&set_qty=0';

            if (items[i].line_id) {
                url += '&line_id=' + encodeURIComponent(items[i].line_id);
            }

            await fetch(url, {
                method: 'GET',
                credentials: 'same-origin'
            });
        }

        if (reloadAfterClear) {
            window.location.href = '/shop/cart';
        }
    }

    async function clearCart() {
        var items = getCartItems();

        if (!items.length) {
            showStatus('Der Warenkorb ist bereits leer.', 'error');
            return;
        }

        if (!window.confirm('Möchten Sie den Warenkorb wirklich leeren?')) {
            return;
        }

        showStatus('Warenkorb wird geleert...', 'success');
        await clearCartWithoutConfirm(true);
    }

    async function saveCartAndClear() {
        var items = getCartItems();

        if (!items.length) {
            showStatus('Der Warenkorb ist leer und kann nicht gespeichert werden.', 'error');
            return;
        }

        var name = window.prompt(
            'Bitte geben Sie einen Namen für diesen Warenkorb ein:',
            'Warenkorb ' + formatDateForFilename(new Date())
        );

        if (!name || !name.trim()) {
            showStatus('Speichern abgebrochen. Es wurde kein Name vergeben.', 'error');
            return;
        }

        name = name.trim();

        var savedCarts = getSavedCarts();

        savedCarts.unshift({
            id: makeCartId(),
            name: name,
            saved_at: new Date().toISOString(),
            items: items
        });

        setSavedCarts(savedCarts);

        showStatus('Warenkorb "' + name + '" wurde gespeichert. Der aktuelle Warenkorb wird jetzt geleert...', 'success');
        await clearCartWithoutConfirm(true);
    }

    async function loadSavedCart(cartId) {
        var savedCarts = getSavedCarts();
        var cart = null;

        savedCarts.forEach(function (item) {
            if (item.id === cartId) {
                cart = item;
            }
        });

        if (!cart || !cart.items || !cart.items.length) {
            showStatus('Der gespeicherte Warenkorb konnte nicht geladen werden.', 'error');
            return;
        }

        showStatus('Gespeicherter Warenkorb "' + cart.name + '" wird geladen...', 'success');

        for (var i = 0; i < cart.items.length; i++) {
            await fetch(
                '/shop/cart/update?product_id=' +
                encodeURIComponent(cart.items[i].product_id) +
                '&set_qty=' +
                encodeURIComponent(cart.items[i].quantity),
                {
                    method: 'GET',
                    credentials: 'same-origin'
                }
            );
        }

        window.location.href = '/shop/cart';
    }

    function deleteSavedCart(cartId) {
        var savedCarts = getSavedCarts().filter(function (cart) {
            return cart.id !== cartId;
        });

        setSavedCarts(savedCarts);
        renderSavedCarts();
        showStatus('Gespeicherter Warenkorb wurde gelöscht.', 'success');
    }

    function openSavedCartModal() {
        var modal = document.getElementById('bafSavedCartModal');

        if (!modal) {
            return;
        }

        renderSavedCarts();
        modal.hidden = false;
        document.body.classList.add('baf-modal-open');
    }

    function closeSavedCartModal() {
        var modal = document.getElementById('bafSavedCartModal');

        if (!modal) {
            return;
        }

        modal.hidden = true;
        document.body.classList.remove('baf-modal-open');
    }

    function renderSavedCarts() {
        var list = document.getElementById('bafSavedCartList');

        if (!list) {
            return;
        }

        var savedCarts = getSavedCarts();

        if (!savedCarts.length) {
            list.innerHTML =
                '<div class="baf-saved-empty">' +
                    '<strong>Keine gespeicherten Warenkörbe vorhanden.</strong>' +
                    '<span>Speichern Sie zuerst einen Warenkorb, um ihn später erneut zu laden.</span>' +
                '</div>';
            return;
        }

        var html = '';

        savedCarts.forEach(function (cart) {
            var itemCount = cart.items ? cart.items.length : 0;
            var savedDate = cart.saved_at ? new Date(cart.saved_at) : null;
            var dateText = savedDate ? savedDate.toLocaleString('de-DE') : '';

            html +=
                '<div class="baf-saved-cart-row" data-cart-id="' + escapeHtml(cart.id) + '">' +
                    '<div class="baf-saved-cart-main">' +
                        '<strong>' + escapeHtml(cart.name || 'Gespeicherter Warenkorb') + '</strong>' +
                        '<span>' + escapeHtml(itemCount) + ' Position(en) · ' + escapeHtml(dateText) + '</span>' +
                    '</div>' +
                    '<div class="baf-saved-cart-actions">' +
                        '<button type="button" class="baf-load-saved-cart-btn" data-cart-id="' + escapeHtml(cart.id) + '">In Warenkorb laden</button>' +
                        '<button type="button" class="baf-delete-saved-cart-btn" data-cart-id="' + escapeHtml(cart.id) + '">Löschen</button>' +
                    '</div>' +
                '</div>';
        });

        list.innerHTML = html;

        list.querySelectorAll('.baf-load-saved-cart-btn').forEach(function (btn) {
            btn.addEventListener('click', function () {
                loadSavedCart(btn.getAttribute('data-cart-id'));
            });
        });

        list.querySelectorAll('.baf-delete-saved-cart-btn').forEach(function (btn) {
            btn.addEventListener('click', function () {
                if (window.confirm('Diesen gespeicherten Warenkorb löschen?')) {
                    deleteSavedCart(btn.getAttribute('data-cart-id'));
                }
            });
        });
    }

    function exportCart() {
        var items = getCartItemsForExport();

        if (!items.length) {
            showStatus('Der Warenkorb ist leer. Es gibt nichts zu exportieren.', 'error');
            return;
        }

        var csvRows = [];

        csvRows.push([
            'Pos.',
            'Teilenummer',
            'Artikel',
            'Menge'
        ].map(csvEscape).join(';'));

        items.forEach(function (item) {
            csvRows.push([
                item.position,
                item.part_number,
                item.name,
                item.quantity
            ].map(csvEscape).join(';'));
        });

        var blob = new Blob([csvRows.join('\n')], {
            type: 'text/csv;charset=utf-8;'
        });

        var url = window.URL.createObjectURL(blob);
        var link = document.createElement('a');
        var filename = 'BAF_Order_' + formatDateForFilename(new Date()) + '.csv';

        link.href = url;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);

        window.URL.revokeObjectURL(url);

        showStatus('Excel-Datei wurde heruntergeladen: ' + filename, 'success');
    }

    var saveBtn = document.getElementById('bafSaveCartBtn');
    var openSavedBtn = document.getElementById('bafOpenSavedCartsBtn');
    var exportBtn = document.getElementById('bafExportCartBtn');
    var clearBtn = document.getElementById('bafClearCartBtn');
    var closeModalBtn = document.getElementById('bafCloseSavedCartModalBtn');
    var modal = document.getElementById('bafSavedCartModal');

    if (saveBtn) {
        saveBtn.addEventListener('click', saveCartAndClear);
    }

    if (openSavedBtn) {
        openSavedBtn.addEventListener('click', openSavedCartModal);
    }

    if (exportBtn) {
        exportBtn.addEventListener('click', exportCart);
    }

    if (clearBtn) {
        clearBtn.addEventListener('click', clearCart);
    }

    if (closeModalBtn) {
        closeModalBtn.addEventListener('click', closeSavedCartModal);
    }

    if (modal) {
        modal.querySelectorAll('[data-baf-close-modal="1"]').forEach(function (el) {
            el.addEventListener('click', closeSavedCartModal);
        });
    }

    document.addEventListener('keydown', function (event) {
        if (event.key === 'Escape') {
            closeSavedCartModal();
        }
    });

    disableProductPageLinks();
});
